import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class SecureCommandExecution {
    public static void main(String[] args) {
        try {
            BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter a command to execute: ");
            String input = reader.readLine().trim();

            // Validate and sanitize user input to prevent command injection
            if (!input.matches("[a-zA-Z0-9\\s]+")) {
                System.err.println("Invalid command format");
                return;
            }

            Process process = Runtime.getRuntime().exec(new String[]{"bash", "-c", input});

            BufferedReader inputReader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line;
            while ((line = inputReader.readLine()) != null) {
                System.out.println(line);
            }
        } catch (IOException e) {
            System.err.println("Error executing command: " + e.getMessage());
        }
    }
